# AWS Security Audit Script
import boto3
import json
from datetime import datetime

class AWSSecurityAuditor:
    def __init__(self):
        self.iam = boto3.client('iam')
        self.ec2 = boto3.client('ec2')
        self.s3 = boto3.client('s3')
        self.findings = []

    def check_iam_password_policy(self):
        """Check IAM password policy strength."""
        try:
            policy = self.iam.get_account_password_policy()
            p = policy['PasswordPolicy']
            issues = []
            if p.get('MinimumPasswordLength', 0) < 14:
                issues.append(f"Password length {p.get('MinimumPasswordLength')} < 14")
            if not p.get('RequireSymbols'):
                issues.append("Symbols not required")
            if not p.get('RequireUppercaseCharacters'):
                issues.append("Uppercase not required")
            if p.get('MaxPasswordAge', 999) > 90:
                issues.append("Password age > 90 days")
            self.findings.extend([{'check': 'IAM_Password', 'issue': i} for i in issues])
            return issues
        except Exception as e:
            return [str(e)]

    def check_public_buckets(self):
        """Find publicly accessible S3 buckets."""
        public_buckets = []
        for bucket in self.s3.list_buckets().get('Buckets', []):
            try:
                acl = self.s3.get_bucket_acl(Bucket=bucket['Name'])
                for grant in acl.get('Grants', []):
                    grantee = grant.get('Grantee', {})
                    if grantee.get('URI') == 'http://acs.amazonaws.com/groups/global/AllUsers':
                        public_buckets.append(bucket['Name'])
            except Exception:
                pass
        return public_buckets

    def check_unused_keys(self):
        """Find IAM users with unused access keys."""
        unused = []
        for user in self.iam.list_users().get('Users', []):
            keys = self.iam.list_access_keys(UserName=user['UserName']).get('AccessKeyMetadata', [])
            for key in keys:
                if key['Status'] == 'Active' and key['CreateDate'].replace(tzinfo=None) < datetime(2025, 1, 1):
                    unused.append(key['AccessKeyId'])
        return unused

    def generate_report(self):
        """Generate security audit report."""
        print("AWS Security Audit Report")
        print("=" * 50)
        print(f"Password Policy Issues: {self.check_iam_password_policy()}")
        print(f"Public Buckets: {self.check_public_buckets()}")
        print(f"Unused Keys: {self.check_unused_keys()}")
        return self.findings
